class Solution:
    def solveEquation(self, equation):
        def parse(side):
            coef = 0
            const = 0
            i = 0
            n = len(side)
            terms = []
            sign = 1
            buf = ''
            # tokenize into signed terms
            i = 0
            while i < n:
                c = side[i]
                if c in '+-' and i != 0:
                    terms.append(buf)
                    buf = c
                else:
                    buf += c
                i += 1
            if buf:
                terms.append(buf)
            for t in terms:
                if t == '' or t == '+' or t == '-':
                    continue
                if t.endswith('x'):
                    num = t[:-1]
                    if num in ('', '+'):
                        coef += 1
                    elif num == '-':
                        coef -= 1
                    else:
                        coef += int(num)
                else:
                    const += int(t)
            return coef, const
        l, r = equation.split('=')
        lc, lk = parse(l)
        rc, rk = parse(r)
        A = lc - rc
        B = rk - lk
        if A == 0:
            if B == 0:
                return 'Infinite solutions'
            return 'No solution'
        return 'x=' + str(B // A)

