class Solution:
    def solveEquation(self, equation):
        import re
        def parse(side):
            coef = 0
            const = 0
            for t in re.findall(r'[+-]?[^+-]+', side):
                if t.endswith('x'):
                    num = t[:-1]
                    if num in ('', '+'):
                        coef += 1
                    elif num == '-':
                        coef -= 1
                    else:
                        coef += int(num)
                else:
                    const += int(t)
            return coef, const
        l, r = equation.split('=')
        lc, lk = parse(l)
        rc, rk = parse(r)
        A = lc - rc
        B = rk - lk
        if A == 0:
            return 'Infinite solutions' if B == 0 else 'No solution'
        return 'x=' + str(B // A)

solutions.javascript:
var solveEquation = function(equation) {
    const parse = (side) => {
        let coef = 0, constant = 0;
        const terms = side.match(/[+-]?[^+-]+/g) || [];
        for (const t of terms) {
            if (t.endsWith('x')) {
                let num = t.slice(0, -1);
                if (num === '' || num === '+') coef += 1;
                else if (num === '-') coef -= 1;
                else coef += parseInt(num, 10);
            } else {
                constant += parseInt(t, 10);
            }
        }
        return [coef, constant];
    };
    const [l, r] = equation.split('=');
    const [lc, lk] = parse(l);
    const [rc, rk] = parse(r);
    const A = lc - rc;
    const B = rk - lk;
    if (A === 0) return B === 0 ? 'Infinite solutions' : 'No solution';
    const q = B / A;
    return 'x=' + Math.trunc(q);
};
